function getVar(name) {
  if (typeof $vars !== 'undefined' && $vars[name] != null && String($vars[name]).trim()) {
    return String($vars[name]).trim();
  }
  return '';
}
const expected = getVar('N8N_WEBHOOK_TOKEN');
if (!expected) throw new Error('N8N_WEBHOOK_TOKEN is not set in n8n Variables');
const req = $input.first().json || {};
const headers = req.headers || {};
const auth = String(headers.authorization || headers.Authorization || '').trim();
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : auth;
if (!token || token !== expected) throw new Error('Unauthorized');
return $input.all();

const raw = $input.first().json;
const row = Array.isArray(raw) ? raw[0] : (raw && raw.id ? raw : (Array.isArray(raw?.body) ? raw.body[0] : raw));
if (!row || !row.id) throw new Error('Draft post not found');
return [{ json: {
  id: row.id,
  captions: row.captions || {},
  platforms: row.platforms || [],
  mediaUrl: row.media_url || row.mediaUrl || null
} }];

const post = $('Flatten Post Data').first().json;
const resp = $input.first().json;
if (resp && resp.success === false) {
  throw new Error(resp.error || 'Failed to fetch social credentials');
}
const creds = Array.isArray(resp?.data) ? resp.data : [];
const platforms = post.platforms || [];
const captions = post.captions || {};
const mediaUrl = post.mediaUrl;
const postId = post.id;
const SUPPORTED = ['instagram', 'facebook', 'x'];
const items = [];
for (const platform of platforms) {
  if (!SUPPORTED.includes(platform)) continue;
  const cred = creds.find(c => c.platform === platform);
  if (!cred) continue;
  items.push({ json: {
    platform,
    caption: (captions[platform] && captions[platform].caption) || '',
    platformToken: cred.access_token,
    mediaUrl,
    postId
  }});
}
if (items.length === 0) throw new Error('No connected platform credentials for requested platforms');
return items;

const item = $input.first().json;
const platform = item.platform;
const token = item.platformToken;
const caption = item.caption || '';
const mediaUrl = item.mediaUrl;
const helpers = this.helpers;

try {
  if (platform === 'facebook') {
    const body = { message: caption };
    if (mediaUrl) body.link = mediaUrl;
    const res = await helpers.httpRequest({
      method: 'POST',
      url: 'https://graph.facebook.com/v18.0/me/feed',
      headers: { Authorization: `Bearer ${token}` },
      body,
      json: true,
    });
    return [{ json: { platform, success: true, provider_id: res.id || null } }];
  }

  if (platform === 'instagram') {
    const pages = await helpers.httpRequest({
      method: 'GET',
      url: 'https://graph.facebook.com/v18.0/me/accounts?fields=instagram_business_account',
      headers: { Authorization: `Bearer ${token}` },
      json: true,
    });
    const page = (pages.data || []).find(p => p.instagram_business_account && p.instagram_business_account.id);
    const igUserId = page?.instagram_business_account?.id;
    if (!igUserId) throw new Error('No instagram_business_account linked to token');
    const containerBody = { caption };
    if (mediaUrl) containerBody.image_url = mediaUrl;
    else throw new Error('Instagram publish requires mediaUrl');
    const container = await helpers.httpRequest({
      method: 'POST',
      url: `https://graph.facebook.com/v18.0/${igUserId}/media`,
      headers: { Authorization: `Bearer ${token}` },
      body: containerBody,
      json: true,
    });
    const creationId = container.id;
    if (!creationId) throw new Error('IG media container creation failed');
    const published = await helpers.httpRequest({
      method: 'POST',
      url: `https://graph.facebook.com/v18.0/${igUserId}/media_publish`,
      headers: { Authorization: `Bearer ${token}` },
      body: { creation_id: creationId },
      json: true,
    });
    return [{ json: { platform, success: true, provider_id: published.id || creationId } }];
  }

  if (platform === 'x') {
    const body = { text: caption };
    const res = await helpers.httpRequest({
      method: 'POST',
      url: 'https://api.twitter.com/2/tweets',
      headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
      body,
      json: true,
    });
    return [{ json: { platform, success: true, provider_id: res.data?.id || null } }];
  }

  throw new Error(`Unsupported platform: ${platform}`);
} catch (error) {
  return [{ json: { platform, success: false, error: error.message || String(error) } }];
}

const postId = $('Publish Request').first().json.body.postId;
const results = $('Publish Platform').all().map(i => i.json);
const failures = results.filter(r => !r.success);
const appUrl = ($vars.NEXUS_APP_URL || 'https://nexusos.knurdz.org').replace(/\/$/, '');
const token = ($vars.N8N_INGEST_TOKEN || $vars.N8N_BOOTSTRAP_TOKEN || '').trim();
if (!token) throw new Error('N8N_INGEST_TOKEN not configured');
const status = failures.length ? 'failed' : 'published';
const error = failures.map(f => `${f.platform}: ${f.error || 'failed'}`).join('; ') || null;
await this.helpers.httpRequest({
  method: 'POST',
  url: `${appUrl}/api/internal/n8n/post-result`,
  headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
  body: { postId, status, error },
  json: true,
});
return [{ json: { postId, status, platforms: results } }];
